const mode = global.get('operationMode') || 'online';

if (mode !== 'online') {
    node.status({ fill: 'yellow', shape: 'ring', text: '오프라인 - 동기화 대기' });
    return null;
}

// 온라인이면 미동기화 데이터 조회 (200건 배치)
msg.topic = `SELECT id, timestamp, farm_id, house_id, sensor_id, value
FROM sensor_data
WHERE synced = 0
ORDER BY timestamp ASC
LIMIT 200`;

return msg;

const rows = msg.payload || [];

if (rows.length === 0) {
    node.status({ fill: 'green', shape: 'dot', text: '동기화 완료 (0건)' });
    return null;
}

const SERVER_URL = env.get('SERVER_URL') || 'http://192.168.137.1:3000';
const API_KEY = env.get('SENSOR_API_KEY') || '';

// 하우스별로 분리
const byHouse = {};
for (const row of rows) {
    const houseKey = row.farm_id + '_' + row.house_id;
    if (!byHouse[houseKey]) {
        byHouse[houseKey] = { farmId: row.farm_id, houseId: row.house_id, rows: [] };
    }
    byHouse[houseKey].rows.push(row);
}

// 하우스별 배치 메시지 생성
const messages = [];
for (const house of Object.values(byHouse)) {
    // 타임스탬프별로 그룹핑
    const grouped = {};
    for (const row of house.rows) {
        if (!grouped[row.timestamp]) {
            grouped[row.timestamp] = {
                timestamp: row.timestamp,
                data: {},
                deviceInfo: { deviceId: 'rpi_0001', ip: '192.168.137.30', version: '1.0.0' }
            };
        }
        grouped[row.timestamp].data[row.sensor_id] = row.value;
    }

    messages.push({
        url: SERVER_URL + '/api/sensors/batch',
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-api-key': API_KEY },
        payload: {
            farmId: house.farmId,
            houseId: house.houseId,
            dataArray: Object.values(grouped)
        },
        _syncIds: house.rows.map(r => r.id),
        _syncCount: house.rows.length
    });
}

const houseCount = Object.keys(byHouse).length;
node.warn('📤 동기화 전송: ' + rows.length + '건 (' + houseCount + '개 하우스)');
node.status({ fill: 'blue', shape: 'dot', text: '전송 중: ' + rows.length + '건' });

// 배열로 반환 → 하우스별 순차 전송
return [messages];

if (msg.statusCode === 201 || msg.statusCode === 200) {
    // 성공 → synced=1 마킹
    const ids = msg._syncIds || [];
    if (ids.length > 0) {
        // ID는 SQLite 자동증가 INTEGER이므로 숫자만 허용
        const safeIds = ids.filter(id => Number.isInteger(id) && id > 0);
        if (safeIds.length === 0) { return [null, null]; }
        // 파라미터화 쿼리: placeholder 동적 생성
        const placeholders = safeIds.map((_, i) => '$' + (i + 1)).join(',');
        msg.topic = 'UPDATE sensor_data SET synced = 1 WHERE id IN (' + placeholders + ')';
        msg.payload = safeIds;
        node.warn('✅ 동기화 성공: ' + msg._syncCount + '건 synced=1');
        node.status({ fill: 'green', shape: 'dot', text: '동기화 완료: ' + msg._syncCount + '건' });
        return [msg, null];
    }
} else {
    node.warn('⚠️ 동기화 실패 (' + msg.statusCode + '): 다음 주기에 재시도');
    node.status({ fill: 'red', shape: 'ring', text: '실패: ' + msg.statusCode });
}

return [null, null];

const mode = global.get('operationMode') || 'online';

if (mode !== 'online') {
    node.status({ fill: 'yellow', shape: 'ring', text: '오프라인 - 규칙 동기화 대기' });
    return null;
}

msg.topic = 'SELECT * FROM automation_rules WHERE synced = 0';
return msg;

const rows = msg.payload || [];

if (rows.length === 0) {
    node.status({ fill: 'green', shape: 'dot', text: '규칙 동기화 완료 (0건)' });
    return null;
}

const SERVER_URL = env.get('SERVER_URL') || 'http://192.168.137.1:3000';
const API_KEY = env.get('SENSOR_API_KEY') || '';
const farmId = env.get('FARM_ID') || 'farm_0001';

// SQLite 행 → PC API 호환 형태로 변환
var rules = rows.map(function(row) {
    var conditions, actions;
    try { conditions = JSON.parse(row.conditions); } catch(e) { conditions = []; }
    try { actions = JSON.parse(row.actions); } catch(e) { actions = []; }
    return {
        id: row.id,
        farmId: row.farm_id,
        houseId: row.house_id,
        name: row.name,
        description: row.description || '',
        enabled: row.enabled === 1,
        conditionLogic: row.condition_logic || 'AND',
        conditions: conditions,
        actions: actions,
        cooldownSeconds: row.cooldown_seconds || 300,
        priority: row.priority || 10,
        lastTriggeredAt: row.last_triggered_at || null,
        triggerCount: row.trigger_count || 0,
        createdAt: row.created_at,
        updatedAt: row.updated_at
    };
});

msg.url = SERVER_URL + '/api/automation/' + farmId + '/sync';
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/json', 'x-api-key': API_KEY };
msg.payload = { rules: rules };
msg._syncRuleIds = rows.map(function(r) { return r.id; });
msg._syncRuleCount = rows.length;

node.warn('📤 규칙 동기화 전송: ' + rows.length + '건');
node.status({ fill: 'blue', shape: 'dot', text: '규칙 전송 중: ' + rows.length + '건' });

return msg;

if (msg.statusCode === 200 || msg.statusCode === 201) {
    var ids = msg._syncRuleIds || [];
    if (ids.length === 0) return null;

    // 문자열 ID → placeholder 동적 생성
    var placeholders = ids.map(function(_, i) { return '$' + (i + 1); }).join(',');
    msg.topic = 'UPDATE automation_rules SET synced = 1 WHERE id IN (' + placeholders + ')';
    msg.payload = ids;

    node.warn('✅ 규칙 동기화 성공: ' + msg._syncRuleCount + '건 synced=1');
    node.status({ fill: 'green', shape: 'dot', text: '규칙 동기화 완료: ' + msg._syncRuleCount + '건' });
    return msg;
} else {
    node.warn('⚠️ 규칙 동기화 실패 (' + msg.statusCode + '): 다음 주기에 재시도');
    node.status({ fill: 'red', shape: 'ring', text: '규칙 동기화 실패: ' + msg.statusCode });
    return null;
}

const row = msg.payload[0] || {};
msg.payload = {
    success: true,
    data: {
        total: row.total || 0,
        synced: row.synced || 0,
        unsynced: row.unsynced || 0,
        oldestUnsynced: row.oldest_unsynced || null,
        operationMode: global.get('operationMode') || 'unknown'
    }
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;
